CREATE DATABASE [FSDM]
    CONTAINMENT = NONE
    ON  PRIMARY
    ( NAME = N'FSDM', FILENAME = N'D:\Databases\FSDM.mdf' , SIZE = 74560KB , MAXSIZE = UNLIMITED, FILEGROWTH = 65536KB ),
    FILEGROUP [Address]
        ( NAME = N'Address', FILENAME = N'D:\Databases\FSDM_Address.ndf' , SIZE = 8192KB , MAXSIZE = UNLIMITED, FILEGROWTH = 65536KB ),
    FILEGROUP [Agreements]
        ( NAME = N'Arrangements', FILENAME = N'D:\Databases\FSDM_Arrangements.ndf' , SIZE = 8192KB , MAXSIZE = UNLIMITED, FILEGROWTH = 65536KB ),
    FILEGROUP [BinaryStorage]
        ( NAME = N'TextImageData', FILENAME = N'D:\Databases\FSDM_TextImageData.ndf' , SIZE = 8192KB , MAXSIZE = UNLIMITED, FILEGROWTH = 65536KB ),
    FILEGROUP [Classifications]
