    FILEGROUP [Geography]
        ( NAME = N'Geography', FILENAME = N'D:\Databases\FSDM_Geography.ndf' , SIZE = 8192KB , MAXSIZE = UNLIMITED, FILEGROWTH = 65536KB ),
