        ( NAME = N'Party', FILENAME = N'D:\Databases\FSDM_Party.ndf' , SIZE = 8192KB , MAXSIZE = UNLIMITED, FILEGROWTH = 65536KB ),
    FILEGROUP [Product]
        ( NAME = N'Product', FILENAME = N'D:\Databases\FSDM_Product.ndf' , SIZE = 8192KB , MAXSIZE = UNLIMITED, FILEGROWTH = 65536KB ),
    FILEGROUP [Resources]
        ( NAME = N'Resources', FILENAME = N'D:\Databases\FSDM_Resources.ndf' , SIZE = 8192KB , MAXSIZE = UNLIMITED, FILEGROWTH = 65536KB ),
    FILEGROUP [Security]
        ( NAME = N'Security', FILENAME = N'D:\Databases\FSDM_Security.ndf' , SIZE = 8192KB , MAXSIZE = UNLIMITED, FILEGROWTH = 65536KB ),
    FILEGROUP [Time]
        ( NAME = N'Time', FILENAME = N'D:\Databases\FSDM_Time.ndf' , SIZE = 8192KB , MAXSIZE = UNLIMITED, FILEGROWTH = 65536KB )
    LOG ON
