--drop view [dbo].[SecurityHierarchyView];
CREATE view [dbo].[SecurityHierarchyView]
AS
with tbl AS
         (
             select st.SecurityTokenID           'id'
                  , st.SecurityTokenFriendlyName 'name'
                  , sxs.ParentSecurityTokenID    'ParentID'
             from Security.SecurityTokenXSecurityToken sxs (nolock)
                      right outer join Security.SecurityToken st (nolock)
                                       on sxs.ChildSecurityTokenID = st.SecurityTokenID
                      left join Security.SecurityToken stChild (nolock)
                                on sxs.ChildSecurityTokenID = stChild.SecurityTokenID
         ),
     SecurityPath
         AS (
         -- anchor
         SELECT id,
                cast([Name] as varchar(250)) 'Name',
                ParentID,
                CAST(([Name]) AS VARCHAR(1000)) AS "Pather",
                CAST((id) AS VARCHAR(1500))     AS "Path"
         FROM tbl
         WHERE ParentId IS NULL
         UNION ALL
         --recursive member
         SELECT t.id,
                cast(t.[Name] as varchar(250)) 'Name',
                t.ParentID,
                CAST((''+ cast(a.id  as varchar) + '/' + cast(t.id as varchar)) AS VARCHAR(1000))  AS "Path",
                CAST((a."Path" + '/' + cast(t.id as varchar(1000))) AS VARCHAR(1500)) AS "PathCrypt"
         FROM tbl AS t  (nolock)
                  JOIN SecurityPath AS a
                       ON t.ParentId = a.id
     )
SELECT s.id,s.Name,s.ParentID,s.Pather,s.Path
FROM SecurityPath s
GO
